import React from "react";
import { useParams, useNavigate } from "react-router-dom";
import Button from "../components/atoms/Button";

// Simulasi data global (bisa diganti dengan context, props, atau fetch dari API)
const dummyMahasiswa = [
  { nim: "123", nama: "Eva Fadhillah", jurusan: "Informatika" },
  { nim: "456", nama: "Dana Putra", jurusan: "Sistem Informasi" },
  // Tambahkan data lainnya jika perlu
];

const MahasiswaDetail = () => {
  const { id } = useParams(); // ambil parameter NIM dari URL
  const navigate = useNavigate();

  // Cari data mahasiswa berdasarkan NIM
  const data = dummyMahasiswa.find((mhs) => mhs.nim === id);

  return (
    <div className="bg-white p-6 shadow rounded-lg max-w-xl mx-auto mt-8">
      <h1 className="text-2xl font-bold mb-4">Detail Mahasiswa</h1>

      {data ? (
        <div className="space-y-2 text-gray-800">
          <p>
            <strong>NIM:</strong> {data.nim}
          </p>
          <p>
            <strong>Nama:</strong> {data.nama}
          </p>
          <p>
            <strong>Jurusan:</strong> {data.jurusan}
          </p>
        </div>
      ) : (
        <p className="text-red-500">Data mahasiswa tidak ditemukan.</p>
      )}

      <div className="mt-6">
        <Button
          className="bg-blue-600 hover:bg-blue-700"
          onClick={() => navigate("/admin/mahasiswa")}
        >
          Kembali ke Daftar Mahasiswa
        </Button>
      </div>
    </div>
  );
};

export default MahasiswaDetail;
